previewCss:
.darma-loader-darma-custom-349 {color: var(--loader-color, #0891b2);
  --loader-secondary-color: #22d3ee;
  --loader-bg: #ffffff;
  display: inline-grid;
  width: 40px;
  aspect-ratio: 1;
}.darma-loader-darma-custom-349:before,.darma-loader-darma-custom-349:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
  background: repeating-conic-gradient(var(--loader-color, #0891b2) 0 60deg,var(--loader-secondary-color, #22d3ee) 0 120deg);
  animation: darma-loader-darma-custom-349-l6 4s linear infinite;
}.darma-loader-darma-custom-349:before {translate: 0 -100%;
}.darma-loader-darma-custom-349:after {padding: 20%;
  mask: conic-gradient(currentColor 0 0) content-box exclude,conic-gradient(currentColor 0 0);
  animation-direction: reverse;
}@keyframes darma-loader-darma-custom-349-l6 {to{rotate: 1turn;
}}

